test.source:
.local $defArticleInPreposition = {$name :inflect number=singular case=accusative to=defArticleInPreposition} .match $defArticleInPreposition
|in die| {{The defArticleInPreposition of '{$name}' is 'in die'.}}
* {{The defArticleInPreposition of '{$name}' is unexpectedly '$defArticleInPreposition'.}}

.local $withDefArticleInPreposition = {$name :inflect number=singular case=dative to=withDefArticleInPreposition} .match $withDefArticleInPreposition
|im Fundort| {{The withDefArticleInPreposition of '{$name}' is 'im Fundort'.}}
* {{The withDefArticleInPreposition of '{$name}' is something else.}}
